{
  "name": "filebrowser-ui",
  "private": true,
  "version": "1.0.0",
  "type": "module",
  "engines": {
    "node": ">=20"
  },
  "scripts": {
    "build": "tsc && node scripts/copy-assets.mjs",
    "watch": "tsc --watch",
    "test": "vitest run",
    "test:backend": "dotnet test TestProject.sln",
    "lint": "oxlint .",
    "lint:fix": "oxlint --fix .",
    "format": "prettier --write .",
    "format:check": "prettier --check .",
    "prepare": "simple-git-hooks"
  },
  "dependencies": {
    "bootstrap-icons": "^1.13.1"
  },
  "devDependencies": {
    "happy-dom": "^15.7.4",
    "lint-staged": "^16.4.0",
    "oxlint": "^1.70.0",
    "prettier": "^3.8.4",
    "simple-git-hooks": "^2.13.1",
    "typescript": "^5.6.3",
    "vitest": "^2.1.4"
  },
  "simple-git-hooks": {
    "pre-commit": "npx lint-staged"
  },
  "lint-staged": {
    "*.{ts,mts,cts,mjs,cjs,js,jsx,tsx,json,jsonc,css,scss,md,yml,yaml}": "prettier --write",
    "*.{ts,mts,cts,mjs,cjs,js,jsx,tsx}": "oxlint --fix",
    "*.cs": "dotnet format TestProject.sln --include"
  }
}

import { defineConfig } from 'vitest/config';

export default defineConfig({
  test: {
    environment: 'happy-dom',
    include: ['src/**/*.test.ts'],
  },
});

/**
 * Render a {@link SearchResult} into the shared results/breadcrumb/status
 * elements: a four-column table (Name | Path | Size | Modified).
 *
 * Operates against the DOM context established by `startApp` (via
 * `render-orchestrator.init`), so it always targets the most recently mounted
 * app.
 */
import type { SearchResult } from '../api.js';
import { buildTable, makeSearchRow, renderBreadcrumb } from './dom-builders.js';
import { getResults, getStatus } from './context.js';

export function renderSearch(result: SearchResult): void {
  // Breadcrumb reflects the search-scope path.
  renderBreadcrumb(result.path);

  // Status footer: 'R results for "q"'
  getStatus().textContent = result.results.length + ' results for "' + result.query + '"';

  // Results table
  const resultsEl = getResults();
  resultsEl.innerHTML = '';
  const table = buildTable(['Name', 'Path', 'Size', 'Modified']);
  const tbody = table.querySelector('tbody')!;

  for (const entry of result.results) {
    tbody.append(makeSearchRow(entry));
  }

  resultsEl.append(table);
}

/**
 * Tests for the search-wrapper DOM restructuring and event rewiring that
 * `src/app.ts`'s `startApp` performs:
 *
 *   - The legacy "Search" `<button>` is removed entirely.
 *   - A `.search-wrapper` div wraps the search `<input>`, a leading search
 *     icon (`bi bi-search search-icon`), and a trailing clear button
 *     (`.clear-btn` containing a `bi bi-x-lg` icon).
 *   - The clear button is an icon-only `<button type="button">` carrying
 *     `aria-label="Clear search"`.
 *   - Child order inside the wrapper is exactly input → search-icon →
 *     clear-btn (the CSS visibility rule for the clear button uses the
 *     general sibling `~` combinator against the input's `:placeholder-shown`).
 *   - `input` events are debounced (200 ms) before triggering `doSearch`;
 *     each new keystroke resets the timer so only the final value searches.
 *   - `Enter` triggers search immediately (no debounce, no stopPropagation).
 *   - `Escape` clears the search AND calls `event.stopPropagation()` so an
 *     enclosing `<dialog>` is not dismissed by the native ESC-to-close
 *     behavior.
 *   - Clicking the clear button invokes `clearSearch`.
 *   - The `DomRefs` passed to `init()` are unchanged: exactly the 5 standard
 *     refs (`results`, `status`, `breadcrumb`, `searchInput`, `uploadInput`)
 *     — the wrapper and clear button are NOT added, because clear-button
 *     visibility is driven purely by CSS (`:placeholder-shown`).
 *
 * The shared `init` from `./render-orchestrator` is wrapped in a pass-through
 * spy (via `vi.mock`) so the DomRefs suite can assert on the exact argument
 * `startApp` passes. The spy delegates to the real `init`, so the app still
 * mounts and renders normally in every other suite here.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest';
import { init } from './render-orchestrator';
import { toBrowseHash, toSearchHash } from '../router';
import { setup, flush, installAppTestLifecycle } from './test-helpers';

// Wrap `init` in a pass-through spy so the DomRefs suite can inspect the exact
// refs object startApp hands to init. The spy calls the real init, so the app
// still binds refs, subscribes hashchange, and kicks off the initial render.
vi.mock('./render-orchestrator', async (importOriginal) => {
  const actual = await importOriginal<typeof import('./render-orchestrator')>();
  return { ...actual, init: vi.fn(actual.init) };
});

installAppTestLifecycle();

// Clear the init spy's call history before each test so call counts reflect
// only the current test's startApp mount. (mockClear, not mockReset: we must
// keep the delegation to the real init.)
beforeEach(() => {
  vi.mocked(init).mockClear();
});

/**
 * Build a fresh app and resolve the search-wrapper sub-elements directly from
 * the rendered DOM.
 *
 * `test-helpers.ts`'s `SetupCtx` now exposes `searchWrapper` /
 * `searchClearBtn` / `searchIcon` (the legacy standalone `searchBtn` field was
 * removed once the search button was dropped from the DOM). This local helper
 * keeps resolving those nodes plus the `.toolbar` handle per-test so the
 * assertions here stay coupled to the rendered DOM rather than to the shared
 * context's field set.
 */
function setupSearchWrapper(options: { hash?: string } = {}) {
  const ctx = setup(options);
  const toolbar = ctx.root.querySelector('.toolbar') as HTMLElement;
  const searchWrapper = ctx.root.querySelector('.search-wrapper') as HTMLElement;
  const searchIcon = searchWrapper.querySelector('.search-icon') as HTMLElement;
  const searchClearBtn = searchWrapper.querySelector('.clear-btn') as HTMLButtonElement;
  return { ...ctx, toolbar, searchWrapper, searchIcon, searchClearBtn };
}

/* ===========================================================================
 * Structure: the "Search" button is gone; a .search-wrapper holds the icons
 * ========================================================================= */
describe('startApp search area structure', () => {
  describe('the legacy "Search" button is removed', () => {
    it('renders no button whose trimmed text content is "Search"', () => {
      const { root } = setup();
      const searchButtons = Array.from(root.querySelectorAll('button')).filter(
        (b) => (b.textContent ?? '').trim() === 'Search',
      );
      expect(searchButtons).toHaveLength(0);
    });

    it('the toolbar has exactly one .btn element — the Upload label', () => {
      // The old search button carried the `btn` class; with it gone, the only
      // `.btn` left in the toolbar is the upload label.
      const { toolbar } = setupSearchWrapper();
      const btns = Array.from(toolbar.querySelectorAll('.btn'));
      expect(btns).toHaveLength(1);
      expect(btns[0].tagName).toBe('LABEL');
      expect((btns[0].textContent ?? '').trim()).toBe('Upload');
    });
  });

  describe('.search-wrapper', () => {
    it('creates a div.search-wrapper inside the toolbar', () => {
      const { toolbar, searchWrapper } = setupSearchWrapper();
      expect(searchWrapper).toBeTruthy();
      expect(searchWrapper.tagName).toBe('DIV');
      expect(searchWrapper.className).toBe('search-wrapper');
      expect(toolbar.contains(searchWrapper)).toBe(true);
    });

    it('places search-wrapper between the breadcrumb and the upload label', () => {
      const { toolbar } = setupSearchWrapper();
      const children = Array.from(toolbar.children);
      expect(children).toHaveLength(3);
      expect(children[0].className).toBe('breadcrumb');
      expect(children[1].className).toBe('search-wrapper');
      expect(children[2].className).toBe('btn'); // upload label
    });

    it('contains the search text input with the "Search..." placeholder', () => {
      const { searchWrapper, searchInput } = setupSearchWrapper();
      expect(searchInput).toBeTruthy();
      expect(searchInput.type).toBe('text');
      expect(searchInput.getAttribute('placeholder')).toBe('Search...');
      expect(searchWrapper.contains(searchInput)).toBe(true);
    });

    it('contains a search icon <i> with classes "bi bi-search search-icon"', () => {
      const { searchWrapper, searchIcon } = setupSearchWrapper();
      expect(searchIcon).toBeTruthy();
      expect(searchIcon.tagName).toBe('I');
      expect(searchIcon.className).toBe('bi bi-search search-icon');
      expect(searchWrapper.contains(searchIcon)).toBe(true);
    });

    it('contains a clear button.clear-btn of type button', () => {
      const { searchWrapper, searchClearBtn } = setupSearchWrapper();
      expect(searchClearBtn).toBeTruthy();
      expect(searchClearBtn.tagName).toBe('BUTTON');
      expect(searchClearBtn.className).toBe('clear-btn');
      expect(searchClearBtn.type).toBe('button');
      expect(searchWrapper.contains(searchClearBtn)).toBe(true);
    });

    it('the clear button carries aria-label="Clear search"', () => {
      // Icon-only button: it has no visible text, so the accessible name must
      // come from aria-label.
      const { searchClearBtn } = setupSearchWrapper();
      expect(searchClearBtn.getAttribute('aria-label')).toBe('Clear search');
    });

    it('the clear button is icon-only (empty trimmed text content)', () => {
      const { searchClearBtn } = setupSearchWrapper();
      expect((searchClearBtn.textContent ?? '').trim()).toBe('');
    });

    it('the clear button contains an <i> icon with classes "bi bi-x-lg"', () => {
      const { searchClearBtn } = setupSearchWrapper();
      const icon = searchClearBtn.querySelector('i');
      expect(icon).toBeTruthy();
      expect(icon?.className).toBe('bi bi-x-lg');
    });

    it('orders children exactly: input → search-icon → clear-btn', () => {
      // ORDER MATTERS: the CSS rule that shows/hides the clear button relies
      // on the general-sibling (~) combinator against the input's
      // :placeholder-shown state, so the input must precede the clear button.
      const { searchWrapper, searchInput, searchIcon, searchClearBtn } = setupSearchWrapper();
      const children = Array.from(searchWrapper.children);
      expect(children).toHaveLength(3);
      expect(children[0]).toBe(searchInput);
      expect(children[1]).toBe(searchIcon);
      expect(children[2]).toBe(searchClearBtn);
    });

    it('the clear button is the only button inside the wrapper', () => {
      const { searchWrapper } = setupSearchWrapper();
      const buttons = searchWrapper.querySelectorAll('button');
      expect(buttons).toHaveLength(1);
    });
  });
});

/* ===========================================================================
 * Event wiring: debounce, Enter, Escape, clear-button click
 * ========================================================================= */
describe('startApp search area events', () => {
  describe('debounced input listener (200 ms)', () => {
    // Fake timers are engaged AFTER the real-timer `await flush()` so the
    // initial render (started by setup → startApp → init → render) can settle
    // using real microtask/timer scheduling. The debounce timer is created
    // only when an `input` event is dispatched below, i.e. after the switch.
    afterEach(() => {
      vi.useRealTimers();
    });

    it('does not search synchronously when the input changes', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      // Synchronously after the input event: still browsing.
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('fires doSearch once 200 ms have elapsed since the last keystroke', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'hello';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toBrowseHash('docs')); // not yet

      vi.advanceTimersByTime(1); // 200 ms total
      expect(window.location.hash).toBe(toSearchHash('hello', 'docs'));
    });

    it('resets the debounce window on each keystroke (only the last value searches)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(150); // first timer has 50 ms left

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input')); // cancels first, starts fresh
      vi.advanceTimersByTime(150); // 150 ms since last keystroke — still inside
      expect(window.location.hash).toBe(toBrowseHash('docs'));

      vi.advanceTimersByTime(50); // 200 ms since last keystroke
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });

    it('trims the query before navigating to the search hash', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = '   spaced   ';
      searchInput.dispatchEvent(new Event('input'));

      vi.advanceTimersByTime(200);
      expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
    });

    it('a second debounce can fire after the first one completes', async () => {
      // Guards against a regression where the timer variable is not reset to
      // null after firing, which would block subsequent searches.
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();
      vi.useFakeTimers();

      searchInput.value = 'a';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(200); // first search fires
      expect(window.location.hash).toBe(toSearchHash('a', 'docs'));

      searchInput.value = 'ab';
      searchInput.dispatchEvent(new Event('input'));
      vi.advanceTimersByTime(199);
      expect(window.location.hash).toBe(toSearchHash('a', 'docs')); // not yet
      vi.advanceTimersByTime(1);
      expect(window.location.hash).toBe(toSearchHash('ab', 'docs'));
    });
  });

  describe('Enter key (immediate search, no debounce)', () => {
    it('triggers search immediately on Enter (no 200 ms wait)', async () => {
      const { searchInput } = setupSearchWrapper({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

      expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
    });

    it('does not stop propagation on Enter', () => {
      // Only Escape stops propagation; Enter must not, so it cannot interfere
      // with any upstream keydown handling.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Enter' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).not.toHaveBeenCalled();
    });
  });

  describe('Escape key (clear + stopPropagation)', () => {
    it('clears the search input value on Escape', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });
      searchInput.value = 'foo';

      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on Escape', () => {
      setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      const searchInput = document.querySelector('.search-wrapper input[type="text"]')!;
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('stops propagation on Escape (so an enclosing dialog is not dismissed)', () => {
      // The search input may live inside a <dialog> (when the browser modal is
      // open). Without stopPropagation, the native dialog ESC-to-close behavior
      // would fire and dismiss the dialog. The handler must swallow the Escape
      // so it only clears the search.
      const { searchInput } = setupSearchWrapper();
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      const stopSpy = vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('clears before stopPropagation order does not matter (both effects occur)', () => {
      const { searchInput } = setupSearchWrapper({ hash: toSearchHash('bar', 'docs') });
      searchInput.value = 'bar';
      const event = new KeyboardEvent('keydown', { key: 'Escape' });
      vi.spyOn(event, 'stopPropagation');

      searchInput.dispatchEvent(event);

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('clear button click', () => {
    it('clears the search input value when the clear button is clicked', () => {
      const { searchClearBtn, searchInput } = setupSearchWrapper({
        hash: toSearchHash('foo', 'docs'),
      });
      searchInput.value = 'foo';

      searchClearBtn.click();

      expect(searchInput.value).toBe('');
    });

    it('navigates back to the browse view for the current path on clear click', () => {
      const { searchClearBtn } = setupSearchWrapper({ hash: toSearchHash('foo', 'docs') });

      searchClearBtn.click();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });
});

/* ===========================================================================
 * DomRefs: init receives exactly the 5 standard refs
 *
 * The clear-button visibility is driven purely by CSS (:placeholder-shown on
 * the input), so startApp must NOT add searchWrapper or searchClearBtn to the
 * refs object it hands to init. Pinning the exact key set guards against a
 * regression that threads the new nodes through the shared context.
 * ========================================================================= */
describe('startApp search area: DomRefs unchanged', () => {
  it('passes exactly the 5 standard refs to init (no searchWrapper / clearBtn)', () => {
    const { searchInput, uploadInput, results, status, breadcrumb } = setupSearchWrapper();

    expect(init).toHaveBeenCalledTimes(1);
    const refs = vi.mocked(init).mock.calls[0][0];
    expect(Object.keys(refs).sort()).toEqual([
      'breadcrumb',
      'results',
      'searchInput',
      'status',
      'uploadInput',
    ]);
    // The refs point at the actual rendered nodes (not clones/duplicates).
    expect(refs.results).toBe(results);
    expect(refs.status).toBe(status);
    expect(refs.breadcrumb).toBe(breadcrumb);
    expect(refs.searchInput).toBe(searchInput);
    expect(refs.uploadInput).toBe(uploadInput);
  });

  it('does not attach a separate clear-button listener via the context (no getSearchClearBtn)', async () => {
    // The context module exposes getters only for the 5 standard refs. The
    // clear-button click handler is wired directly in startApp (imperative
    // addEventListener), not through a context ref — so importing the context
    // must not surface a clear-button getter. This is a structural guard: if a
    // future change adds the clear button to DomRefs, a matching getter would
    // appear here.
    const ctx = await import('./context');
    expect(typeof (ctx as Record<string, unknown>).getSearchClearBtn).toBe('undefined');
    expect(typeof (ctx as Record<string, unknown>).getSearchWrapper).toBe('undefined');
  });
});

/**
 * Tests for `renderSearch` — the search-result renderer (table headers, rows,
 * per-result columns, directory-name navigation, file-name download, and the
 * status footer).
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 *
 * Contract decisions encoded here (carried over from the monolith):
 *  - Clicking a directory result name navigates (asserted via
 *    `window.location.hash`); clicking a search-result FILE name opens its
 *    download URL. The spec does not pin the file-open mechanism, so that test
 *    accepts EITHER an `<a href={downloadUrl}>` OR a `window.open(downloadUrl)`
 *    call.
 *  - The results table uses a `<thead>` (header `<th>` row) and a `<tbody>`
 *    (data `<td>` rows). Column order for search is
 *    `Name | Path | Size | Modified`.
 *  - `renderSearch` operates against the DOM context `startApp` establishes
 *    (module-level element refs), so every test calls `setupCleared()` first.
 */
import { describe, it, expect, vi } from 'vitest';
import { renderSearch } from '../app';
import type { FileEntry } from '../api';
import { toBrowseHash } from '../router';
import {
  setupCleared,
  fileEntry,
  dataRows,
  cellsOf,
  rowByName,
  clickNameLink,
  ISO_FMT,
  installAppTestLifecycle,
} from './test-helpers';

installAppTestLifecycle();

/* ===========================================================================
 * renderSearch — table, rows, navigation
 * ========================================================================= */
describe('renderSearch', () => {
  it('builds a table with header Name | Path | Size | Modified', async () => {
    const { results } = await setupCleared();
    renderSearch({ query: 'foo', path: '', results: [] });

    const table = results.querySelector('table');
    expect(table).toBeTruthy();
    const headers = Array.from(table!.querySelectorAll('th')).map((h) => h.textContent!.trim());
    expect(headers).toEqual(['Name', 'Path', 'Size', 'Modified']);
  });

  it('renders one row per result with its path, size and modified date', async () => {
    const results_data: FileEntry[] = [
      fileEntry({ name: 'a.txt', path: 'docs/a.txt', size: 1536 }),
      fileEntry({ name: 'b.txt', path: 'other/b.txt', size: 0 }),
    ];
    const { results } = await setupCleared();
    renderSearch({ query: 'q', path: '', results: results_data });

    const table = results.querySelector('table')!;
    expect(dataRows(table)).toHaveLength(2);
    const cells = cellsOf(rowByName(table, 'a.txt')!);
    expect(cells[1].textContent?.trim()).toBe('docs/a.txt'); // Path
    expect(cells[2].textContent?.trim()).toBe('1.5 KB'); // Size
    expect(cells[3].textContent?.trim()).toBe(ISO_FMT); // Modified
  });

  it('clicking a directory result name navigates to toBrowseHash(entry.path)', async () => {
    const dir = fileEntry({ name: 'matchdir', path: 'docs/matchdir', isDirectory: true });
    const { results } = await setupCleared();
    renderSearch({ query: 'match', path: '', results: [dir] });

    clickNameLink(rowByName(results.querySelector('table')!, 'matchdir')!);
    expect(window.location.hash).toBe(toBrowseHash('docs/matchdir'));
  });

  it('clicking a file result name opens api.downloadUrl(entry.path)', async () => {
    const file = fileEntry({ name: 'match.txt', path: 'docs/match.txt', isDirectory: false });
    const { results } = await setupCleared();
    renderSearch({ query: 'match', path: '', results: [file] });
    const expectedUrl = '/api/files/download?path=' + encodeURIComponent('docs/match.txt');

    const nameCell = cellsOf(rowByName(results.querySelector('table')!, 'match.txt')!)[0];
    const link = nameCell.querySelector('a, button') as HTMLElement | null;
    expect(link).toBeTruthy();

    // The spec says clicking "opens" the download URL. Two reasonable mechanisms
    // are acceptable: an <a href={downloadUrl}> (mirroring the Download control)
    // or a click handler that calls window.open(downloadUrl). Accept either so
    // the test does not over-constrain the implementation choice.
    const hrefOpens = link!.getAttribute('href') === expectedUrl;
    const openSpy = vi.spyOn(window, 'open').mockReturnValue(null);
    link!.click();
    const openedViaWindow = openSpy.mock.calls.some((c) => c[0] === expectedUrl);
    expect(hrefOpens || openedViaWindow).toBe(true);
  });

  it('shows the result count and query in the status footer', async () => {
    const { status } = await setupCleared();
    renderSearch({
      query: 'foo',
      path: '',
      results: [fileEntry({ name: 'a.txt' }), fileEntry({ name: 'b.txt' })],
    });

    expect(status.textContent).toContain('2 results for "foo"');
  });
});

/**
 * Tests for the toolbar handlers — the search button / Enter-key handler, the
 * clear-search handler, and the upload (change) handler, including the
 * per-file upload error-handling contract.
 *
 * Split out of the former `src/app.test.ts` monolith (task-29). Shared
 * fixtures, DOM scaffolding, and the per-test fetch stub come from
 * `./test-helpers`.
 *
 * Environment: the project-default `happy-dom` (these tests need a DOM).
 */
import { describe, it, expect, vi } from 'vitest';
import { toBrowseHash, toSearchHash } from '../router';
import { normalizeRelativePath } from '../format';
import { mockResponse } from '../test-utils/mock-response';
import {
  setup,
  flush,
  browseResult,
  fileEntry,
  joinPathHelper,
  fetchMock,
  installAppTestLifecycle,
} from './test-helpers';
import { clearSearch, pickAndUploadInto } from './toolbar-handlers';

installAppTestLifecycle();

/* ===========================================================================
 * Toolbar handlers
 * ========================================================================= */
describe('toolbar handlers', () => {
  describe('search', () => {
    it('navigates to a search hash 200ms after the user types in the input (debounced)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000); // settle initial render

        searchInput.value = 'hello world';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));

        // Not yet — debounce hasn't fired
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(200);
        expect(window.location.hash).toBe(toSearchHash('hello world', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('resets the debounce timer on each keystroke (only fires after 200ms of silence)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'h';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // not enough
        searchInput.value = 'he';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(150); // 150ms since last keystroke, still not enough
        expect(window.location.hash).toBe(toBrowseHash('docs'));

        vi.advanceTimersByTime(50); // now 200ms since last keystroke
        expect(window.location.hash).toBe(toSearchHash('he', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('trims the query before navigating', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '   spaced   ';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toSearchHash('spaced', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search (returns to browse) when the query becomes empty', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = '';
        searchInput.dispatchEvent(new Event('input', { bubbles: true }));
        vi.advanceTimersByTime(200);

        expect(window.location.hash).toBe(toBrowseHash('docs'));
      } finally {
        vi.useRealTimers();
      }
    });

    it('clears the search input and navigates to browse when the X (clear) button is clicked', async () => {
      const { searchInput, searchClearBtn } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchClearBtn.click();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('clears the search input and navigates to browse when Escape is pressed', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'foo';
      searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Escape' }));

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('Escape key stops propagation (does not close the parent <dialog>)', async () => {
      const { searchInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const parentEl = searchInput.closest('.file-browser') ?? document.body;
      parentEl.addEventListener('keydown', () => {
        // should NOT fire if stopPropagation worked
      });

      const event = new KeyboardEvent('keydown', { key: 'Escape', bubbles: true });
      const stopSpy = vi.spyOn(event, 'stopPropagation');
      searchInput.dispatchEvent(event);

      expect(stopSpy).toHaveBeenCalled();
    });

    it('still navigates immediately when Enter is pressed (bypasses debounce)', async () => {
      vi.useFakeTimers();
      try {
        const { searchInput } = setup({ hash: toBrowseHash('docs') });
        vi.advanceTimersByTime(1000);

        searchInput.value = 'foo';
        searchInput.dispatchEvent(new KeyboardEvent('keydown', { key: 'Enter' }));

        // Enter fires immediately, no debounce wait needed
        expect(window.location.hash).toBe(toSearchHash('foo', 'docs'));
      } finally {
        vi.useRealTimers();
      }
    });
  });

  describe('clearSearch', () => {
    // clearSearch() is the explicit "clear the search box and return to browse"
    // handler (e.g. an "×" / Clear button). It must (1) blank the shared search
    // input, (2) read the CURRENT route's path, and (3) navigate to the browse
    // hash for that path — mirroring doSearch()'s empty-query branch, but as a
    // dedicated, unconditional entry point that also wipes the input text.

    it('resets the search input value to an empty string', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'leftover query';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
    });

    it('navigates to the browse hash for the current browse path', async () => {
      setup({ hash: toBrowseHash('docs/sub') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(normalizeRelativePath('docs/sub')));
    });

    it('uses the current route path even when the app is showing a search view', async () => {
      // A search route carries its own `path` (the search scope); clearSearch
      // must drop the query and return to browsing THAT path, not root.
      setup({ hash: toSearchHash('anything', 'docs') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('normalizes the current path before building the browse hash', async () => {
      // A trailing slash (or backslashes) in the current path is collapsed by
      // normalizeRelativePath so the resulting browse hash is canonical.
      setup({ hash: toBrowseHash('docs/') });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });

    it('navigates to the root browse hash when the current path is empty', async () => {
      setup({ hash: '' });
      await flush();

      clearSearch();
      await flush();

      expect(window.location.hash).toBe(toBrowseHash(''));
    });

    it('clears the input and navigates to browse together', async () => {
      const { searchInput } = setup({ hash: toSearchHash('foo', 'docs') });
      await flush();

      searchInput.value = 'stale text';
      clearSearch();
      await flush();

      expect(searchInput.value).toBe('');
      expect(window.location.hash).toBe(toBrowseHash('docs'));
    });
  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(
          ([, init]) =>
            ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '',
        );
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(
        uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs'))),
      ).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(fetchMock.mock.calls.some(([u]) => String(u).includes('/upload'))).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });

  describe('pickAndUploadInto (upload into an arbitrary folder)', () => {
    // Exercises pickAndUploadInto directly: it builds a transient
    // <input type=file multiple>, awaits its change/cancel, uploads every
    // chosen file into the GIVEN path (not the current route), then removes
    // the input and re-renders — mirroring handleUpload's contract but with a
    // caller-chosen destination.

    /** Grab the transient picker input that pickAndUploadInto appended to body. */
    function findPickerInput(): HTMLInputElement | undefined {
      // The transient input is a DIRECT child of <body>; the toolbar upload
      // input lives inside <label class="btn">, so its parent is not body.
      return Array.from(document.querySelectorAll('input[type=file]')).find(
        (i) => i.parentElement === document.body,
      ) as HTMLInputElement | undefined;
    }

    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    function uploadCalls(): [string, RequestInit | undefined][] {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
    }

    it('creates a hidden <input type=file multiple> appended to body, then uploads each file into the given path', async () => {
      setup({ hash: toBrowseHash('current/dir') });
      await flush();

      // Suspend on the awaited picker: do NOT await yet.
      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput, 'a transient picker input must be appended to body').toBeTruthy();
      expect(pickInput!.type).toBe('file');
      expect(pickInput!.multiple).toBe(true);

      setFiles(pickInput!, ['a.txt', 'b.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Uploads target the GIVEN path, NOT the current route.
      expect(uploadCalls()).toHaveLength(2);
      expect(
        uploadCalls().every(([u]) =>
          String(u).includes('path=' + encodeURIComponent('target/folder')),
        ),
      ).toBe(true);
      // The transient input was removed after the upload loop.
      expect(findPickerInput()).toBeUndefined();
    });

    it('uploads nothing and removes the input when the picker is cancelled (no files)', async () => {
      setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      expect(pickInput).toBeTruthy();

      // Dismiss the picker without choosing — the `cancel` event resolves
      // the awaited promise with an empty list.
      pickInput!.dispatchEvent(new Event('cancel'));
      await p;
      await settle();

      expect(uploadCalls()).toHaveLength(0);
      expect(findPickerInput()).toBeUndefined();
    });

    it('surfaces per-file failures in the status footer while still uploading the rest', async () => {
      fetchMock.mockImplementation(async (url: string, init?: RequestInit) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && file.name === 'bad.txt') {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          return mockResponse({ body: browseResult({ path: 'target/folder', entries: [] }) });
        }
        return mockResponse({ status: 200, body: {} });
      });
      const { status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      const p = pickAndUploadInto('target/folder');
      const pickInput = findPickerInput();
      setFiles(pickInput!, ['good.txt', 'bad.txt']);
      pickInput!.dispatchEvent(new Event('change'));
      await p;
      await settle();

      // Both were attempted; only bad.txt is flagged.
      expect(
        uploadCalls().map(([, init]) => ((init!.body as FormData).get('file') as File).name),
      ).toEqual(['good.txt', 'bad.txt']);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });
  });
});

// @vitest-environment node
/**
 * Static-asset tests for `wwwroot/index.html` — the host page that boots the
 * SPA (`<div id="app">` + `<script type="module" src="dist/app.js">`).
 *
 * Pinned to the `node` environment because these tests only inspect the HTML
 * source: they read the file from disk and assert on its markup. They need no
 * DOM, and pinning here keeps them fast and side-effect-free. (Parsing the page
 * with happy-dom's `DOMParser` would instead try to fetch/evaluate the page's
 * `<script src="dist/app.js">` and emit unhandled rejections, so the assertions
 * below parse the raw string deterministically instead.)
 *
 * The headline contract under test is the UI/UX accessibility requirement that
 * users who arrive with JavaScript disabled/blocked see an explanatory
 * `<noscript>` message rather than a blank page, while every pre-existing
 * bootstrap element (charset, viewport, title, stylesheet, mount point, module
 * script) is left intact.
 */
import { describe, it, expect } from 'vitest';
import { readFileSync } from 'node:fs';
import { resolve, dirname } from 'node:path';
import { fileURLToPath } from 'node:url';

const __dirname = dirname(fileURLToPath(import.meta.url));
const HTML_PATH = resolve(__dirname, '../wwwroot/index.html');
const HTML = readFileSync(HTML_PATH, 'utf8');

/* ===========================================================================
 * Helpers
 * ========================================================================= */

/**
 * Extract the full `<noscript>...</noscript>` block. Non-greedy so it captures
 * only the first (and, per the "exactly one" assertion, only) noscript element.
 */
const NOSCRIPT_RE = /<noscript\b[^>]*>([\s\S]*?)<\/noscript>/i;
const noscriptMatch = HTML.match(NOSCRIPT_RE);
const noscriptBlock = noscriptMatch?.[0] ?? '';
const noscriptInner = noscriptMatch?.[1] ?? '';

/**
 * Pull an attribute's value out of a markup fragment, honoring whichever quote
 * character (`"` or `'`) delimits it. This matters here because the fallback's
 * inline `style="..."` contains single-quoted font names (e.g. 'Segoe UI')
 * inside a double-quoted attribute, so a naive `[^"']*` capture would stop at
 * the first single quote.
 */
function getAttribute(markup: string, name: string): string | null {
  const re = new RegExp(`${name}\\s*=\\s*(?:"([^"]*)"|'([^']*)')`, 'i');
  const m = markup.match(re);
  return m ? (m[1] ?? m[2] ?? '') : null;
}

/**
 * Relative luminance of a CSS color literal, per the sRGB / WCAG definition.
 * Used to assert the fallback text is *light enough to read* on the dark
 * `#1e1e1e` body background defined in `dist/app.css`, rather than merely
 * "some color". Accepts `#rgb`, `#rrggbb`, and `rgb()/rgba()` forms plus a
 * small allow-list of light named colors.
 */
function isLightColor(value: string): boolean {
  const v = value.trim().toLowerCase();
  let r: number;
  let g: number;
  let b: number;

  const hex = v.match(/^#([0-9a-f]{3}|[0-9a-f]{6})$/);
  if (hex) {
    let h = hex[1];
    if (h.length === 3) {
      h = h
        .split('')
        .map((c) => c + c)
        .join('');
    }
    r = parseInt(h.slice(0, 2), 16);
    g = parseInt(h.slice(2, 4), 16);
    b = parseInt(h.slice(4, 6), 16);
  } else if (v.startsWith('rgb')) {
    const nums = v.match(/\d+(\.\d+)?/g);
    if (!nums || nums.length < 3) return false;
    [r, g, b] = nums.map(Number);
  } else if (
    [
      'white',
      'whitesmoke',
      'aliceblue',
      'azure',
      'ivory',
      'snow',
      'seashell',
      'floralwhite',
      'mintcream',
    ].includes(v)
  ) {
    return true;
  } else {
    // Unknown format: cannot prove it is light, so fail closed.
    return false;
  }

  const toLinear = (c: number) => {
    const s = c / 255;
    return s <= 0.03928 ? s / 12.92 : ((s + 0.055) / 1.055) ** 2.4;
  };
  const L = 0.2126 * toLinear(r) + 0.7152 * toLinear(g) + 0.0722 * toLinear(b);
  // WCAG's light/dark crossover (~0.179). #1e1e1e → ~0.013 (dark),
  // #e6e6e6 (the theme text color) → ~0.79 (light).
  return L > 0.179;
}

/* ===========================================================================
 * Document skeleton + preserved bootstrap markup
 * ========================================================================= */
describe('wwwroot/index.html — document skeleton', () => {
  it('is an HTML5 document', () => {
    expect(HTML).toMatch(/^<!DOCTYPE html>/i);
    expect(HTML).toMatch(/<html\b/i);
  });

  it('has <head> and <body> sections', () => {
    expect(HTML).toMatch(/<head\b/i);
    expect(HTML).toMatch(/<\/head>/i);
    expect(HTML).toMatch(/<body\b/i);
    expect(HTML).toMatch(/<\/body>/i);
  });
});

describe('wwwroot/index.html — preserved bootstrap markup', () => {
  it('declares a UTF-8 charset', () => {
    expect(HTML).toMatch(/<meta\s+charset=["']?utf-8["']?/i);
  });

  it('keeps the responsive viewport meta', () => {
    expect(HTML).toMatch(/<meta\s+name=["']viewport["']/i);
    expect(HTML).toMatch(/width=device-width/i);
    expect(HTML).toMatch(/initial-scale=1/i);
  });

  it('keeps the "File Browser" title', () => {
    expect(HTML).toMatch(/<title>\s*File Browser\s*<\/title>/i);
  });

  it('still links the compiled stylesheet dist/app.css', () => {
    expect(HTML).toMatch(/<link[^>]+href=["']dist\/app\.css["']/i);
  });

  it('still mounts the SPA into an empty #app container', () => {
    expect(HTML).toMatch(/<div\s+id=["']app["']>\s*<\/div>/i);
  });

  it('still loads the app as an ES module script dist/app.js', () => {
    expect(HTML).toMatch(/<script[^>]+type=["']module["'][^>]+src=["']dist\/app\.js["']/i);
  });
});

/* ===========================================================================
 * <noscript> fallback — the accessibility fix under test
 * ========================================================================= */
describe('wwwroot/index.html — <noscript> fallback', () => {
  it('contains exactly one <noscript> element', () => {
    const openingTags = HTML.match(/<noscript\b/gi) ?? [];
    expect(openingTags.length).toBe(1);
    expect(noscriptBlock, 'a <noscript>...</noscript> block must exist').toBeTruthy();
  });

  it('is located inside <body> (not in <head>)', () => {
    const bodyOpen = HTML.search(/<body\b/i);
    const bodyClose = HTML.search(/<\/body>/i);
    const nsStart = HTML.search(/<noscript\b/i);
    const nsEnd = nsStart >= 0 ? nsStart + noscriptBlock.length : -1;

    expect(bodyOpen, '<body> must open before the noscript').toBeGreaterThanOrEqual(0);
    expect(bodyClose, '</body> must exist').toBeGreaterThan(bodyOpen);
    expect(nsStart, 'noscript must start after <body> opens').toBeGreaterThan(bodyOpen);
    expect(nsEnd, 'noscript must end before </body>').toBeLessThan(bodyClose);
  });

  it('is placed after the #app mount point', () => {
    // The fix places the fallback immediately after `<div id="app"></div>`;
    // it must not precede the mount container.
    const appIdx = HTML.search(/<div\s+id=["']app["']/i);
    const nsIdx = HTML.search(/<noscript\b/i);
    expect(appIdx).toBeGreaterThanOrEqual(0);
    expect(nsIdx).toBeGreaterThan(appIdx);
  });

  it('provides a non-empty, human-readable message', () => {
    const text = noscriptInner
      .replace(/<[^>]+>/g, ' ')
      .replace(/\s+/g, ' ')
      .trim();
    expect(text.length).toBeGreaterThan(20);
  });

  it('tells the user the app requires JavaScript', () => {
    expect(noscriptInner.toLowerCase()).toContain('javascript');
  });

  it('is actionable — instructs the user to enable JavaScript', () => {
    expect(noscriptInner.toLowerCase()).toContain('enable');
  });

  it('uses only plain text — no interactive controls or scripts inside <noscript>', () => {
    // A fallback shown when scripting is off cannot rely on buttons, links,
    // forms, or scripts. Allow text + simple structural tags only.
    expect(
      /<(button|a|input|form|select|textarea|script|iframe|object|embed)\b/i.test(noscriptInner),
    ).toBe(false);
  });

  it('styles the message so it is visible against the dark theme background', () => {
    // dist/app.css paints the body background #1e1e1e (near-black). If the
    // stylesheet also fails to load, the fallback must still be legible, so the
    // message needs an inline light foreground color.
    const style = getAttribute(noscriptInner, 'style');
    expect(style, 'the message element must carry an inline style attribute').not.toBeNull();

    // The foreground `color` declaration (guarded so it does not match
    // `background-color` / `border-color`).
    const colorMatch = style!.toLowerCase().match(/(?:^|;)\s*color\s*:\s*([^;]+)/i);
    expect(colorMatch, 'inline style must set a foreground `color`').not.toBeNull();

